 1→{
 2→  "name": "@basra/shared",
 3→  "version": "1.0.0",
 4→  "private": true,
 5→  "main": "src/index.ts",
 6→  "types": "src/index.ts",
 7→  "scripts": {
 8→    "build": "tsc",
