  1→import { create } from 'zustand';
  2→import {
  3→  Card,
  4→  GamePhase,
  5→  CardPlayedPayload,
  6→  GameStartPayload,
  7→  CardsDealtPayload,
  8→  RoundEndPayload,
  9→  GameOverPayload,
 10→} from '@basra/shared';
 11→
 12→interface PlayerInfo {
 13→  id: string;
 14→  nickname: string;
 15→  score: number;
 16→  capturedCount: number;
 17→  basras: number;
 18→  jackBasras: number;
 19→}
 20→
 21→interface GameStore {
 22→  phase: GamePhase;
 23→  hand: Card[];
 24→  table: Card[];
 25→  deckRemaining: number;
 26→  currentTurn: string | null;
 27→  dealer: string | null;
 28→  myId: string | null;
 29→  opponentCardCount: number;
 30→  roundNumber: number;
 31→  targetScore: number;
 32→  players: PlayerInfo[];
 33→
 34→  // Last play animation data
 35→  lastPlay: CardPlayedPayload | null;
 36→
 37→  // Round end data
 38→  roundEndData: RoundEndPayload | null;
 39→
 40→  // Game over data
 41→  gameOverData: GameOverPayload | null;
 42→
 43→  // Whether opponent is connected
 44→  opponentConnected: boolean;
 45→
 46→  // Actions
 47→  setMyId: (id: string) => void;
 48→  onGameStart: (data: GameStartPayload, myId: string) => void;
 49→  onCardsDealt: (data: CardsDealtPayload) => void;
 50→  onCardPlayed: (data: CardPlayedPayload) => void;
 51→  onRoundEnd: (data: RoundEndPayload) => void;
 52→  onGameOver: (data: GameOverPayload) => void;
 53→  setOpponentConnected: (connected: boolean) => void;
 54→  isMyTurn: () => boolean;
 55→  reset: () => void;
 56→}
 57→
 58→export const useGameStore = create<GameStore>((set, get) => ({
 59→  phase: 'waiting',
 60→  hand: [],
 61→  table: [],
 62→  deckRemaining: 0,
 63→  currentTurn: null,
 64→  dealer: null,
 65→  myId: null,
 66→  opponentCardCount: 0,
 67→  roundNumber: 0,
 68→  targetScore: 121,
 69→  players: [],
 70→  lastPlay: null,
 71→  roundEndData: null,
 72→  gameOverData: null,
 73→  opponentConnected: true,
 74→
 75→  setMyId: (id) => set({ myId: id }),
 76→
 77→  onGameStart: (data, myId) =>
 78→    set({
 79→      phase: 'playing',
 80→      hand: data.hand,
 81→      table: data.tableCards,
 82→      deckRemaining: data.deckRemaining,
 83→      currentTurn: data.currentTurn,
 84→      dealer: data.dealer,
 85→      myId,
 86→      opponentCardCount: data.opponentCardCount,
 87→      roundNumber: data.roundNumber,
 88→      targetScore: data.targetScore,
 89→      players: data.players.map((p) => ({
 90→        id: p.id,
 91→        nickname: p.nickname,
 92→        score: p.score,
 93→        capturedCount: 0,
 94→        basras: 0,
 95→        jackBasras: 0,
 96→      })),
 97→      lastPlay: null,
 98→      roundEndData: null,
 99→      gameOverData: null,
100→    }),
101→
102→  onCardsDealt: (data) =>
103→    set({
104→      hand: data.hand,
105→      deckRemaining: data.deckRemaining,
106→      opponentCardCount: data.opponentCardCount,
107→    }),
108→
109→  onCardPlayed: (data) => {
110→    const state = get();
111→    const isMe = data.playerId === state.myId;
112→
113→    set({
114→      table: data.tableAfter,
115→      currentTurn: data.currentTurn,
116→      lastPlay: data,
117→      // If I played, remove the card from my hand
118→      hand: isMe
119→        ? state.hand.filter((c) => c.id !== data.card.id)
120→        : state.hand,
121→      // If opponent played, decrement their count
122→      opponentCardCount: isMe
123→        ? state.opponentCardCount
124→        : state.opponentCardCount - 1,
125→      // Update captured counts
126→      players: state.players.map((p) =>
127→        p.id === data.playerId
128→          ? { ...p, capturedCount: data.playerCapturedCount }
129→          : p
130→      ),
131→    });
132→  },
133→
134→  onRoundEnd: (data) =>
135→    set({
136→      phase: 'round-end',
137→      roundEndData: data,
138→      players: data.players.map((p) => ({
139→        id: p.id,
140→        nickname: p.nickname,
141→        score: p.totalScore,
142→        capturedCount: p.capturedCount,
143→        basras: p.basras,
144→        jackBasras: p.jackBasras,
145→      })),
146→    }),
147→
148→  onGameOver: (data) =>
149→    set({
150→      phase: 'game-over',
151→      gameOverData: data,
152→    }),
153→
154→  setOpponentConnected: (connected) => set({ opponentConnected: connected }),
155→
156→  isMyTurn: () => {
157→    const state = get();
158→    return state.currentTurn === state.myId;
159→  },
160→
161→  reset: () =>
162→    set({
163→      phase: 'waiting',
164→      hand: [],
165→      table: [],
166→      deckRemaining: 0,
167→      currentTurn: null,
168→      dealer: null,
169→      myId: null,
170→      opponentCardCount: 0,
171→      roundNumber: 0,
172→      players: [],
173→      lastPlay: null,
174→      roundEndData: null,
175→      gameOverData: null,
176→      opponentConnected: true,
177→    }),
178→}));
179→

  1→import { TouchableOpacity, View, Text, StyleSheet } from 'react-native';
  2→import Animated, {
  3→  useAnimatedStyle,
  4→  useSharedValue,
  5→  withSpring,
  6→  withTiming,
  7→} from 'react-native-reanimated';
  8→import { Card as CardType } from '@basra/shared';
  9→import { getSuitSymbol, getSuitColor, getDisplayRank } from '../utils/cardImages';
 10→import { colors, cardDimensions } from '../theme';
 11→
 12→interface CardProps {
 13→  card: CardType;
 14→  faceUp?: boolean;
 15→  onPress?: (card: CardType) => void;
 16→  selected?: boolean;
 17→  disabled?: boolean;
 18→  small?: boolean;
 19→}
 20→
 21→const AnimatedTouchable = Animated.createAnimatedComponent(TouchableOpacity);
 22→
 23→export default function Card({
 24→  card,
 25→  faceUp = true,
 26→  onPress,
 27→  selected = false,
 28→  disabled = false,
 29→  small = false,
 30→}: CardProps) {
 31→  const scale = useSharedValue(1);
 32→
 33→  const suitColor = getSuitColor(card.suit);
 34→  const suitSymbol = getSuitSymbol(card.suit);
 35→  const displayRank = getDisplayRank(card.rank);
 36→
 37→  const w = small ? cardDimensions.width * 0.7 : cardDimensions.width;
 38→  const h = small ? cardDimensions.height * 0.7 : cardDimensions.height;
 39→
 40→  const animatedStyle = useAnimatedStyle(() => ({
 41→    transform: [
 42→      { scale: scale.value },
 43→      { translateY: selected ? -10 : 0 },
 44→    ],
 45→  }));
 46→
 47→  const handlePressIn = () => {
 48→    scale.value = withSpring(0.95);
 49→  };
 50→
 51→  const handlePressOut = () => {
 52→    scale.value = withSpring(1);
 53→  };
 54→
 55→  const handlePress = () => {
 56→    if (!disabled && onPress) {
 57→      onPress(card);
 58→    }
 59→  };
 60→
 61→  if (!faceUp) {
 62→    return (
 63→      <View style={[styles.card, styles.cardBack, { width: w, height: h }]}>
 64→        <View style={styles.backPattern}>
 65→          <Text style={styles.backText}>B</Text>
 66→        </View>
 67→      </View>
 68→    );
 69→  }
 70→
 71→  return (
 72→    <AnimatedTouchable
 73→      style={[
 74→        styles.card,
 75→        { width: w, height: h },
 76→        selected && styles.cardSelected,
 77→        disabled && styles.cardDisabled,
 78→        animatedStyle,
 79→      ]}
 80→      onPress={handlePress}
 81→      onPressIn={handlePressIn}
 82→      onPressOut={handlePressOut}
 83→      activeOpacity={0.8}
 84→      disabled={disabled}
 85→    >
 86→      <Text style={[styles.rankTop, { color: suitColor }]}>
 87→        {displayRank}
 88→      </Text>
 89→      <Text style={[styles.suitCenter, { color: suitColor, fontSize: small ? 18 : 24 }]}>
 90→        {suitSymbol}
 91→      </Text>
 92→      <Text style={[styles.rankBottom, { color: suitColor }]}>
