 1→import { PlayerState, RoundScoreResult } from './types';
 2→import { MOST_CARDS_BONUS, BASRA_POINTS, JACK_BASRA_POINTS } from './constants';
 3→
 4→/**
 5→ * Calculate round scores for both players.
 6→ */
 7→export function calculateRoundScores(
 8→  player1: PlayerState,
 9→  player2: PlayerState
10→): RoundScoreResult {
11→  let p1Points = 0;
12→  let p2Points = 0;
13→
14→  // Most captured cards bonus (30 points)
15→  if (player1.capturedCount > player2.capturedCount) {
16→    p1Points += MOST_CARDS_BONUS;
17→  } else if (player2.capturedCount > player1.capturedCount) {
18→    p2Points += MOST_CARDS_BONUS;
19→  }
20→  // If equal, neither gets the bonus
21→
22→  // Basra points
23→  p1Points += player1.basras * BASRA_POINTS;
24→  p1Points += player1.jackBasras * JACK_BASRA_POINTS;
25→
26→  p2Points += player2.basras * BASRA_POINTS;
27→  p2Points += player2.jackBasras * JACK_BASRA_POINTS;
28→
29→  return {
30→    player1Cards: player1.capturedCount,
31→    player2Cards: player2.capturedCount,
32→    player1RoundPoints: p1Points,
33→    player2RoundPoints: p2Points,
34→  };
35→}
36→
37→/**
38→ * Check if a player has won (reached target score).
39→ */
40→export function checkWinner(
41→  players: [PlayerState, PlayerState],
42→  targetScore: number
43→): PlayerState | null {
44→  // Both could reach target in same round - higher score wins
45→  const [p1, p2] = players;
46→  const p1Reached = p1.score >= targetScore;
47→  const p2Reached = p2.score >= targetScore;
48→
49→  if (p1Reached && p2Reached) {
50→    return p1.score >= p2.score ? p1 : p2;
51→  }
52→  if (p1Reached) return p1;
53→  if (p2Reached) return p2;
54→  return null;
55→}
